text <- readLines("manuscript_research_note.tex")
res_start <- grep("Consistent with the culture conversion model, the between-person differences", text)
disc_start <- grep("\\\\section\\{Discussion and Conclusion\\}", text)

new_res <- c(
  "Consistent with the culture conversion model, the between-person differences (the person-mean effects) demonstrate the durable power of cultural capital, but reveal that it operates through highly specialized channels (see Table \\ref{tab:network_stability} and Figure \\ref{fig:unified_cultural_effects}). Persons who display persistently high engagement in \\emph{Out-of-Home Arts/Entertainment} ($\\beta \\approx 0.38, p < 0.001$) and \\emph{Reading/Homebound Culture} ($\\beta \\approx 0.30, p < 0.01$) sustain significantly higher frequencies of informal social interaction with elective ties, specifically friends. Conversely, the durable effect on structurally prescribed family members is driven entirely by one specific dimension: \\emph{Reading/Homebound Culture} ($\\beta \\approx 0.53, p < 0.001$). Durable engagement in arts or sports has strictly zero baseline effect on interacting with family. Finally, possessing a high average repertoire of \\emph{Sports Culture} ($\\beta \\approx 0.30, p < 0.001$) and \\emph{Arts/Entertainment} ($\\beta \\approx 0.17, p < 0.01$) significantly raises the chances of remaining structurally integrated into important social foci of interaction, such as voluntary organizations. This structural integration effect aligns with the idea that retaining memberships is largely a matter of keeping alive the public, elective network ties that bind an individual to an organization \\citep{popielarz1995}. While this cross-sectional ``between'' effect does not offer definitive evidence of strict causality, it firmly embeds prior cross-sectional findings \\citep{lizardo2006, cebula2023social-fe1, jaeger2026} in a rigorous longitudinal modeling framework.",
  "",
  "The Mundlak specification also allows us to evaluate the \\textit{within}-person effects---whether a temporary spike in an individual's cultural tastes over their own average translates to immediate gains in connectivity. These effects come closer to capturing any causal effects that gains or losses in cultural capital have on network ties. Here, the dynamics mirror the specialized channels found in the baseline effects, as visualized in Figure \\ref{fig:unified_cultural_effects}. Temporary expansions in \\emph{Arts/Entertainment} yield a significant immediate boost to informal socializing for friends ($\\beta \\approx 0.22, p < 0.05$), while a temporary burst in \\emph{Reading/Homebound} practices yields an immediate boost to interacting with kin ($\\beta \\approx 0.26, p < 0.05$). However, for structural integration into voluntary organizations, the within-person effects for all cultural dimensions are entirely non-significant ($p > 0.05$). This suggests that while temporary spikes in specific cultural engagements immediately boost fluid, informal socializing in matching relational domains, it is the durable, trait-like possession of cultural capital (the stable between-person difference) that is strictly required to sustain structural integration into formal organizations.",
  ""
)

text <- c(text[1:(res_start-1)], new_res, text[disc_start:length(text)])
writeLines(text, "manuscript_research_note.tex")
